{"path": "src/db.rs", "content": "use crate::api::*;
use crate::distance::l2_distance_squared;
use std::sync::RwLock;
use rayon::prelude::*;

/// A vector database entry
#[derive(Clone)]
struct VectorEntry {
    id: u64,
    vector: Vec<f32>,
}

pub struct VectorDB {
    vectors: RwLock<Vec<VectorEntry>>,
}

impl VectorDB {
    pub fn new() -> Self {
        Self {
            vectors: RwLock::new(Vec::new()),
        }
    }

    pub fn insert(&self, id: u64, vector: Vec<f32>) {
        let mut guard = self.vectors.write().unwrap();
        guard.push(VectorEntry { id, vector });
    }

    pub fn bulk_insert(&self, vectors: Vec<(u64, Vec<f32>)>) -> usize {
        let mut guard = self.vectors.write().unwrap();
        let count = vectors.len();
        for (id, vector) in vectors {
            guard.push(VectorEntry { id, vector });
        }
        count
    }

    pub fn search(&self, query: &[f32], top_k: u32) -> Vec<SearchResult> {
        let vectors = self.vectors.read().unwrap();

        if vectors.is_empty() {
            return Vec::new();
        }

        let top_k = top_k as usize;

        // Compute distances in parallel using rayon
        let mut results: Vec<(u64, f64)> = vectors
            .par_iter()
            .map(|entry| {
                let dist = l2_distance_squared(query, &entry.vector);
                (entry.id, dist)
            })
            .collect();

        // Partial sort to get top-k
        results.partial_sort_by(top_k, |a, b| a.1.partial_cmp(&b.1).unwrap());
        results.truncate(top_k);

        // Convert to SearchResult (taking sqrt for actual distance)
        results
            .into_iter()
            .map(|(id, dist_sq)| SearchResult {
                id,
                distance: dist_sq.sqrt(),
            })
            .collect()
    }
}
"}

