{"path": "src/distance.rs", "content": "use std::arch::x86_64::*;

const DIMENSION: usize = 128;

/// Compute L2 distance squared between two 128-dim vectors using AVX-512
#[inline]
pub fn l2_distance_squared(a: &[f32; DIMENSION], b: &[f32; DIMENSION]) -> f64 {
    unsafe {
        // Process 16 elements at a time using AVX-512 (128 elements = 8 iterations)
        let mut acc0 = _mm512_setzero_ps();
        let mut acc1 = _mm512_setzero_ps();
        let mut acc2 = _mm512_setzero_ps();
        let mut acc3 = _mm512_setzero_ps();

        // Unroll loop for better instruction-level parallelism
        let mut i = 0;
        while i < 128 {
            let va0 = _mm512_loadu_ps(a.as_ptr().add(i));
            let vb0 = _mm512_loadu_ps(b.as_ptr().add(i));
            let diff0 = _mm512_sub_ps(va0, vb0);
            acc0 = _mm512_fmadd_ps(diff0, diff0, acc0);

            let va1 = _mm512_loadu_ps(a.as_ptr().add(i + 16));
            let vb1 = _mm512_loadu_ps(b.as_ptr().add(i + 16));
            let diff1 = _mm512_sub_ps(va1, vb1);
            acc1 = _mm512_fmadd_ps(diff1, diff1, acc1);

            let va2 = _mm512_loadu_ps(a.as_ptr().add(i + 32));
            let vb2 = _mm512_loadu_ps(b.as_ptr().add(i + 32));
            let diff2 = _mm512_sub_ps(va2, vb2);
            acc2 = _mm512_fmadd_ps(diff2, diff2, acc2);

            let va3 = _mm512_loadu_ps(a.as_ptr().add(i + 48));
            let vb3 = _mm512_loadu_ps(b.as_ptr().add(i + 48));
            let diff3 = _mm512_sub_ps(va3, vb3);
            acc3 = _mm512_fmadd_ps(diff3, diff3, acc3);

            i += 64;
        }

        // Combine accumulators
        acc0 = _mm512_add_ps(acc0, acc1);
        acc2 = _mm512_add_ps(acc2, acc3);
        acc0 = _mm512_add_ps(acc0, acc2);

        _mm512_reduce_add_ps(acc0) as f64
    }
}

/// Compute L2 distance between two vectors using AVX-512
pub fn l2_distance(a: &[f32], b: &[f32]) -> f64 {
    assert_eq!(a.len(), b.len());

    let len = a.len();
    let mut i = 0;
    let mut sum = 0.0f64;

    unsafe {
        // Process 16 elements at a time using AVX-512
        if len >= 16 {
            let mut acc = _mm512_setzero_ps();

            while i + 16 <= len {
                let va = _mm512_loadu_ps(a.as_ptr().add(i));
                let vb = _mm512_loadu_ps(b.as_ptr().add(i));
                let diff = _mm512_sub_ps(va, vb);
                acc = _mm512_fmadd_ps(diff, diff, acc);
                i += 16;
            }

            sum = _mm512_reduce_add_ps(acc) as f64;
        }

        // Process remaining elements
        while i < len {
            let diff = a[i] - b[i];
            sum += (diff * diff) as f64;
            i += 1;
        }
    }

    sum.sqrt()
}
"}

