{"path": "src/db.rs", "content": "use crate::api::*;
use crate::distance::l2_distance_squared;
use std::sync::RwLock;
use rayon::prelude::*;
use std::collections::BinaryHeap;
use std::cmp::Ordering;

const DIMENSION: usize = 128;

/// Result item with ordering by distance (for max-heap of largest to remove)
#[derive(Clone, Copy)]
struct HeapItem {
    id: u64,
    distance: f64,
}

impl PartialEq for HeapItem {
    fn eq(&self, other: &Self) -> bool {
        self.distance == other.distance
    }
}

impl Eq for HeapItem {}

impl PartialOrd for HeapItem {
    fn partial_cmp(&self, other: &Self) -> Option<Ordering> {
        // Max-heap: larger distances stay at top
        self.distance.partial_cmp(&other.distance)
    }
}

impl Ord for HeapItem {
    fn cmp(&self, other: &Self) -> Ordering {
        self.partial_cmp(other).unwrap()
    }
}

pub struct VectorDB {
    ids: RwLock<Vec<u64>>,
    vectors: RwLock<Vec<f32>>, // Flat storage: all vectors concatenated
}

impl VectorDB {
    pub fn new() -> Self {
        Self {
            ids: RwLock::new(Vec::with_capacity(1_100_000)),
            vectors: RwLock::new(Vec::with_capacity(1_100_000 * DIMENSION)),
        }
    }

    pub fn insert(&self, id: u64, vector: Vec<f32>) {
        let mut ids_guard = self.ids.write().unwrap();
        let mut vecs_guard = self.vectors.write().unwrap();
        ids_guard.push(id);
        vecs_guard.extend_from_slice(&vector[..DIMENSION]);
    }

    pub fn bulk_insert(&self, vectors: Vec<(u64, Vec<f32>)>) -> usize {
        let mut ids_guard = self.ids.write().unwrap();
        let mut vecs_guard = self.vectors.write().unwrap();
        let count = vectors.len();
        ids_guard.reserve(count);
        vecs_guard.reserve(count * DIMENSION);
        for (id, vector) in vectors {
            ids_guard.push(id);
            vecs_guard.extend_from_slice(&vector[..DIMENSION]);
        }
        count
    }

    pub fn search(&self, query: &[f32], top_k: u32) -> Vec<SearchResult> {
        let ids = self.ids.read().unwrap();
        let vectors = self.vectors.read().unwrap();

        if ids.is_empty() {
            return Vec::new();
        }

        let top_k = top_k as usize;
        let num_vectors = ids.len();
        let query_slice = &query[..DIMENSION];

        // Create slices for parallel iteration
        let distances: Vec<(u64, f64)> = (0..num_vectors)
            .into_par_iter()
            .map(|i| {
                let vec_start = i * DIMENSION;
                let vec_slice = &vectors[vec_start..vec_start + DIMENSION];
                let dist = l2_distance_squared(query_slice, vec_slice);
                (ids[i], dist)
            })
            .collect();

        // Use binary heap to find top-k smallest distances
        let mut heap = BinaryHeap::with_capacity(top_k + 1);

        for (id, dist) in distances {
            heap.push(HeapItem { id, distance: dist });
            if heap.len() > top_k {
                heap.pop();
            }
        }

        // Convert to results
        let mut results: Vec<SearchResult> = heap
            .into_vec()
            .into_iter()
            .map(|item| SearchResult {
                id: item.id,
                distance: item.distance.sqrt(),
            })
            .collect();

        results.sort_by(|a, b| a.distance.partial_cmp(&b.distance).unwrap());
        results
    }
}
"}

{"path": "src/db.rs", "content": "use crate::api::*;
use crate::distance::l2_distance_squared;
use std::sync::{RwLock, Arc};
use rayon::prelude::*;
use std::collections::BinaryHeap;
use std::cmp::Ordering;
use rand::prelude::*;
use rand::SeedableRng;

const DIMENSION: usize = 128;
const NUM_BUCKETS: usize = 200;  // Number of IVF clusters
const BUCKETS_TO_SEARCH: usize = 20;  // Number of closest buckets to search
const SUBSAMPLE_FOR_CENTROIDS: usize = 50000;  // Sample size for k-means init

/// Result item with ordering by distance (for max-heap of largest to remove)
#[derive(Clone, Copy)]
struct HeapItem {
    id: u64,
    distance: f64,
}

impl PartialEq for HeapItem {
    fn eq(&self, other: &Self) -> bool {
        self.distance == other.distance
    }
}

impl Eq for HeapItem {}

impl PartialOrd for HeapItem {
    fn partial_cmp(&self, other: &Self) -> Option<Ordering> {
        // Max-heap: larger distances stay at top
        self.distance.partial_cmp(&other.distance)
    }
}

impl Ord for HeapItem {
    fn cmp(&self, other: &Self) -> Ordering {
        self.partial_cmp(other).unwrap()
    }
}

/// IVF Bucket containing vectors assigned to a centroid
struct Bucket {
    ids: Vec<u64>,
    // Flat storage of vectors in this bucket
    vectors: Vec<f32>,
}

impl Bucket {
    fn new() -> Self {
        Self {
            ids: Vec::new(),
            vectors: Vec::new(),
        }
    }

    fn add(&mut self, id: u64, vector: &[f32]) {
        self.ids.push(id);
        self.vectors.extend_from_slice(vector);
    }

    fn clear(&mut self) {
        self.ids.clear();
        self.vectors.clear();
    }
}

pub struct VectorDB {
    // All vectors and ids stored flat
    all_ids: RwLock<Vec<u64>>,
    all_vectors: RwLock<Vec<f32>>,

    // IVF index
    centroids: RwLock<Vec<Vec<f32>>>, // NUM_BUCKETS x DIMENSION
    buckets: RwLock<Vec<Bucket>>,

    // Flag to track if index needs rebuild
    index_built: RwLock<bool>,
}

impl VectorDB {
    pub fn new() -> Self {
        let buckets: Vec<Bucket> = (0..NUM_BUCKETS).map(|_| Bucket::new()).collect();

        Self {
            all_ids: RwLock::new(Vec::with_capacity(1_100_000)),
            all_vectors: RwLock::new(Vec::with_capacity(1_100_000 * DIMENSION)),
            centroids: RwLock::new(Vec::new()),
            buckets: RwLock::new(buckets),
            index_built: RwLock::new(false),
        }
    }

    pub fn insert(&self, id: u64, vector: Vec<f32>) {
        let mut ids_guard = self.all_ids.write().unwrap();
        let mut vecs_guard = self.all_vectors.write().unwrap();
        ids_guard.push(id);
        vecs_guard.extend_from_slice(&vector[..DIMENSION]);
        *self.index_built.write().unwrap() = false;
    }

    pub fn bulk_insert(&self, vectors: Vec<(u64, Vec<f32>)>) -> usize {
        let mut ids_guard = self.all_ids.write().unwrap();
        let mut vecs_guard = self.all_vectors.write().unwrap();
        let count = vectors.len();
        ids_guard.reserve(count);
        vecs_guard.reserve(count * DIMENSION);
        for (id, vector) in vectors {
            ids_guard.push(id);
            vecs_guard.extend_from_slice(&vector[..DIMENSION]);
        }
        drop(ids_guard);
        drop(vecs_guard);

        // Build index after bulk insert
        self.build_index();

        count
    }

    fn build_index(&self) {
        let ids = self.all_ids.read().unwrap();
        let vectors = self.all_vectors.read().unwrap();

        if ids.len() < NUM_BUCKETS {
            return;
        }

        let num_vectors = ids.len();

        // Initialize centroids using k-means++ style sampling
        let mut centroids: Vec<Vec<f32>> = Vec::with_capacity(NUM_BUCKETS);
        let mut rng = StdRng::seed_from_u64(42);

        // Sample vectors for centroid initialization
        let sample_size = num_vectors.min(SUBSAMPLE_FOR_CENTROIDS);
        let mut sample_indices: Vec<usize> = (0..num_vectors).collect();
        sample_indices.shuffle(&mut rng);

        // Simple k-means: randomly pick NUM_BUCKETS vectors as centroids from subsample
        for i in 0..NUM_BUCKETS.min(sample_size) {
            let idx = sample_indices[i];
            let start = idx * DIMENSION;
            let centroid: Vec<f32> = vectors[start..start + DIMENSION].to_vec();
            centroids.push(centroid);
        }

        // If we don't have enough centroids, duplicate some
        while centroids.len() < NUM_BUCKETS {
            let idx = rng.gen_range(0..centroids.len());
            centroids.push(centroids[idx].clone());
        }

        // Run a few k-means iterations to refine centroids
        for _ in 0..5 {
            // Assign vectors to centroids
            let mut new_centroids: Vec<Vec<f32>> = vec![vec![0.0f32; DIMENSION]; NUM_BUCKETS];
            let mut counts: Vec<usize> = vec![0; NUM_BUCKETS];

            for i in 0..num_vectors {
                let start = i * DIMENSION;
                let vec_slice = &vectors[start..start + DIMENSION];

                // Find nearest centroid
                let mut min_dist = f64::MAX;
                let mut best_centroid = 0;

                for (cidx, centroid) in centroids.iter().enumerate() {
                    let dist = l2_distance_squared(vec_slice, centroid);
                    if dist < min_dist {
                        min_dist = dist;
                        best_centroid = cidx;
                    }
                }

                // Add to new centroid accumulator
                for d in 0..DIMENSION {
                    new_centroids[best_centroid][d] += vec_slice[d];
                }
                counts[best_centroid] += 1;
            }

            // Compute new centroids
            for cidx in 0..NUM_BUCKETS {
                if counts[cidx] > 0 {
                    for d in 0..DIMENSION {
                        centroids[cidx][d] = new_centroids[cidx][d] / counts[cidx] as f32;
                    }
                }
            }
        }

        // Clear and repopulate buckets
        let mut buckets = self.buckets.write().unwrap();
        for bucket in buckets.iter_mut() {
            bucket.clear();
        }

        // Assign vectors to buckets
        for i in 0..num_vectors {
            let start = i * DIMENSION;
            let vec_slice = &vectors[start..start + DIMENSION];

            // Find nearest centroid
            let mut min_dist = f64::MAX;
            let mut best_bucket = 0;

            for (cidx, centroid) in centroids.iter().enumerate() {
                let dist = l2_distance_squared(vec_slice, centroid);
                if dist < min_dist {
                    min_dist = dist;
                    best_bucket = cidx;
                }
            }

            buckets[best_bucket].add(ids[i], vec_slice);
        }

        // Store centroids
        *self.centroids.write().unwrap() = centroids;
        *self.index_built.write().unwrap() = true;
    }

    pub fn search(&self, query: &[f32], top_k: u32) -> Vec<SearchResult> {
        // Check if index is built
        let index_built = *self.index_built.read().unwrap();

        if !index_built {
            self.build_index();
        }

        let centroids = self.centroids.read().unwrap();
        let buckets = self.buckets.read().unwrap();

        if centroids.is_empty() {
            // Fall back to brute force
            return self.brute_force_search(query, top_k);
        }

        let top_k = top_k as usize;
        let query_slice = &query[..DIMENSION];

        // Find closest BUCKETS_TO_SEARCH centroids
        let mut centroid_dists: Vec<(usize, f64)> = centroids
            .par_iter()
            .enumerate()
            .map(|(idx, centroid)| {
                let dist = l2_distance_squared(query_slice, centroid);
                (idx, dist)
            })
            .collect();

        centroid_dists.sort_by(|a, b| a.1.partial_cmp(&b.1).unwrap());
        centroid_dists.truncate(BUCKETS_TO_SEARCH);

        // Collect all vectors from selected buckets
        let mut candidates: Vec<(u64, f64)> = Vec::new();

        for (bucket_idx, _) in centroid_dists {
            let bucket = &buckets[bucket_idx];
            let num_vecs = bucket.ids.len();

            for i in 0..num_vecs {
                let start = i * DIMENSION;
                let vec_slice = &bucket.vectors[start..start + DIMENSION];
                let dist = l2_distance_squared(query_slice, vec_slice);
                candidates.push((bucket.ids[i], dist));
            }
        }

        // Use binary heap to find top-k smallest distances
        let mut heap = BinaryHeap::with_capacity(top_k + 1);

        for (id, dist) in candidates {
            heap.push(HeapItem { id, distance: dist });
            if heap.len() > top_k {
                heap.pop();
            }
        }

        // Convert to results
        let mut results: Vec<SearchResult> = heap
            .into_vec()
            .into_iter()
            .map(|item| SearchResult {
                id: item.id,
                distance: item.distance.sqrt(),
            })
            .collect();

        results.sort_by(|a, b| a.distance.partial_cmp(&b.distance).unwrap());
        results
    }

    fn brute_force_search(&self, query: &[f32], top_k: u32) -> Vec<SearchResult> {
        let ids = self.all_ids.read().unwrap();
        let vectors = self.all_vectors.read().unwrap();

        if ids.is_empty() {
            return Vec::new();
        }

        let top_k = top_k as usize;
        let num_vectors = ids.len();
        let query_slice = &query[..DIMENSION];

        let distances: Vec<(u64, f64)> = (0..num_vectors)
            .into_par_iter()
            .map(|i| {
                let vec_start = i * DIMENSION;
                let vec_slice = &vectors[vec_start..vec_start + DIMENSION];
                let dist = l2_distance_squared(query_slice, vec_slice);
                (ids[i], dist)
            })
            .collect();

        let mut heap = BinaryHeap::with_capacity(top_k + 1);

        for (id, dist) in distances {
            heap.push(HeapItem { id, distance: dist });
            if heap.len() > top_k {
                heap.pop();
            }
        }

        let mut results: Vec<SearchResult> = heap
            .into_vec()
            .into_iter()
            .map(|item| SearchResult {
                id: item.id,
                distance: item.distance.sqrt(),
            })
            .collect();

        results.sort_by(|a, b| a.distance.partial_cmp(&b.distance).unwrap());
        results
    }
}
"}

