use crate::distance::l2_distance_squared;
use std::sync::RwLock;
use rayon::prelude::*;
use std::collections::BinaryHeap;
use std::cmp::Ordering;

const DIMENSION: usize = 128;
const NUM_RANDOM_PROJECTIONS: usize = 10;  // 2^10 = 1024 buckets

/// Result item with ordering by distance (for max-heap of largest to remove)
#[derive(Clone, Copy)]
struct HeapItem {
    id: u64,
    distance: f64,
}

impl PartialEq for HeapItem {
    fn eq(&self, other: &Self) -> bool {
        self.distance == other.distance
    }
}

impl Eq for HeapItem {}

impl PartialOrd for HeapItem {
    fn partial_cmp(&self, other: &Self) -> Option<Ordering> {
        // Max-heap: larger distances stay at top
        self.distance.partial_cmp(&other.distance)
    }
}

impl Ord for HeapItem {
    fn cmp(&self, other: &Self) -> Ordering {
        self.partial_cmp(other).unwrap()
    }
}

/// Bucket index entry
struct Bucket {
    ids: Vec<u64>,
    vectors: Vec<f32>,  // Flat storage
}

pub struct VectorDB {
    // Random projection hyperplanes (each hyperplane is a normal vector)
    projections: Vec<[f32; DIMENSION]>,

    // Buckets indexed by hash (0 to 2^NUM_RANDOM_PROJECTIONS - 1)
    buckets: RwLock<Vec<Bucket>>,

    // Linear storage for brute force fallback
    all_ids: RwLock<Vec<u64>>,
    all_vectors: RwLock<Vec<f32>>,

    // Whether index is initialized
    initialized: RwLock<bool>,
}

impl VectorDB {
    pub fn new() -> Self {
        // Generate random projections
        let mut projections = Vec::with_capacity(NUM_RANDOM_PROJECTIONS);
        for _ in 0..NUM_RANDOM_PROJECTIONS {
            let mut proj = [0.0f32; DIMENSION];
            for d in 0..DIMENSION {
                // Simple random normal approx using rand-like approach
                proj[d] = fastrand::f32() * 2.0 - 1.0;
            }
            projections.push(proj);
        }

        // Initialize empty buckets (we'll create them on demand)
        let num_buckets = 1 << NUM_RANDOM_PROJECTIONS;
        let buckets: Vec<Bucket> = (0..num_buckets)
            .map(|_| Bucket { ids: Vec::new(), vectors: Vec::new() })
            .collect();

        Self {
            projections,
            buckets: RwLock::new(buckets),
            all_ids: RwLock::new(Vec::with_capacity(1_100_000)),
            all_vectors: RwLock::new(Vec::with_capacity(1_100_000 * DIMENSION)),
            initialized: RwLock::new(false),
        }
    }

    fn compute_hash(&self, vector: &[f32]) -> usize {
        let mut hash = 0usize;
        for (i, proj) in self.projections.iter().enumerate() {
            // Compute dot product
            let mut dot = 0.0f32;
            for d in 0..DIMENSION {
                dot += vector[d] * proj[d];
            }
            // Set bit if dot product is positive
            if dot > 0.0 {
                hash |= 1 << i;
            }
        }
        hash
    }

    pub fn insert(&self, id: u64, vector: Vec<f32>) {
        let mut ids_guard = self.all_ids.write().unwrap();
        let mut vecs_guard = self.all_vectors.write().unwrap();
        ids_guard.push(id);
        vecs_guard.extend_from_slice(&vector[..DIMENSION]);
    }

    pub fn bulk_insert(&self, vectors: Vec<(u64, Vec<f32>)>) -> usize {
        let mut ids_guard = self.all_ids.write().unwrap();
        let mut vecs_guard = self.all_vectors.write().unwrap();
        let count = vectors.len();
        ids_guard.reserve(count);
        vecs_guard.reserve(count * DIMENSION);
        for (id, vector) in vectors {
            ids_guard.push(id);
            vecs_guard.extend_from_slice(&vector[..DIMENSION]);
        }
        drop(ids_guard);
        drop(vecs_guard);

        self.build_index();

        count
    }

    fn build_index(&self) {
        let ids = self.all_ids.read().unwrap();
        let vectors = self.all_vectors.read().unwrap();
        let num_vectors = ids.len();

        if num_vectors == 0 {
            return;
        }

        let mut buckets = self.buckets.write().unwrap();

        // Assign vectors to buckets
        for i in 0..num_vectors {
            let start = i * DIMENSION;
            let vec_slice = &vectors[start..start + DIMENSION];
            let hash = self.compute_hash(vec_slice);

            buckets[hash].ids.push(ids[i]);
            buckets[hash].vectors.extend_from_slice(vec_slice);
        }

        *self.initialized.write().unwrap() = true;
    }

    pub fn search(&self, query: &[f32], top_k: u32) -> Vec<SearchResult> {
        let initialized = *self.initialized.read().unwrap();

        if !initialized {
            return self.brute_force_search(query, top_k);
        }

        let query_slice = &query[..DIMENSION];
        let query_hash = self.compute_hash(query_slice);

        let buckets = self.buckets.read().unwrap();
        let top_k = top_k as usize;

        // Search the query's bucket and nearby buckets (by flipping bits)
        // Start with just the exact bucket first
        let mut candidates: Vec<(u64, f64)> = Vec::new();

        // Search exact bucket
        self.search_bucket(&buckets[query_hash], query_slice, &mut candidates);

        // Search buckets with 1-bit difference
        for bit in 0..NUM_RANDOM_PROJECTIONS {
            let neighbor_hash = query_hash ^ (1 << bit);
            self.search_bucket(&buckets[neighbor_hash], query_slice, &mut candidates);
        }

        // If we don't have enough candidates, search 2-bit differences
        if candidates.len() < top_k * 10 {
            for bit1 in 0..NUM_RANDOM_PROJECTIONS {
                for bit2 in (bit1+1)..NUM_RANDOM_PROJECTIONS {
                    let neighbor_hash = query_hash ^ (1 << bit1) ^ (1 << bit2);
                    self.search_bucket(&buckets[neighbor_hash], query_slice, &mut candidates);
                }
            }
        }

        // Find top-k from candidates
        let mut heap = BinaryHeap::with_capacity(top_k + 1);
        for (id, dist) in candidates {
            heap.push(HeapItem { id, distance: dist });
            if heap.len() > top_k {
                heap.pop();
            }
        }

        // Convert to results
        let mut results: Vec<SearchResult> = heap
            .into_vec()
            .into_iter()
            .map(|item| SearchResult {
                id: item.id,
                distance: item.distance.sqrt(),
            })
            .collect();

        results.sort_by(|a, b| a.distance.partial_cmp(&b.distance).unwrap());
        results
    }

    fn search_bucket(&self, bucket: &Bucket, query: &[f32], candidates: &mut Vec<(u64, f64)>) {
        let num_vecs = bucket.ids.len();
        for i in 0..num_vecs {
            let start = i * DIMENSION;
            let vec_slice = &bucket.vectors[start..start + DIMENSION];
            let dist = l2_distance_squared(query, vec_slice);
            candidates.push((bucket.ids[i], dist));
        }
    }

    fn brute_force_search(&self, query: &[f32], top_k: u32) -> Vec<SearchResult> {
        let ids = self.all_ids.read().unwrap();
        let vectors = self.all_vectors.read().unwrap();

        if ids.is_empty() {
            return Vec::new();
        }

        let top_k = top_k as usize;
        let num_vectors = ids.len();
        let query_slice = &query[..DIMENSION];

        let distances: Vec<(u64, f64)> = (0..num_vectors)
            .into_par_iter()
            .map(|i| {
                let vec_start = i * DIMENSION;
                let vec_slice = &vectors[vec_start..vec_start + DIMENSION];
                let dist = l2_distance_squared(query_slice, vec_slice);
                (ids[i], dist)
            })
            .collect();

        let mut heap = BinaryHeap::with_capacity(top_k + 1);

        for (id, dist) in distances {
            heap.push(HeapItem { id, distance: dist });
            if heap.len() > top_k {
                heap.pop();
            }
        }

        let mut results: Vec<SearchResult> = heap
            .into_vec()
            .into_iter()
            .map(|item| SearchResult {
                id: item.id,
                distance: item.distance.sqrt(),
            })
            .collect();

        results.sort_by(|a, b| a.distance.partial_cmp(&b.distance).unwrap());
        results
    }
}
