const DIMENSION: usize = 128;
const NUM_BUCKETS: usize = 64;  // Fewer buckets
const BUCKET_MASK: usize = NUM_BUCKETS - 1;  // For modulo operation

/// Result item with ordering by distance (for max-heap of largest to remove)
